select count(*) from postgres.comments as c, postgres.posts as p, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v where p.id = pl.postid and p.id = v.postid and p.id = ph.postid and p.id = c.postid and c.score=0 and p.favoritecount>=0 and p.creationdate>=timestamp '2010-07-23 02:00:12' and p.creationdate<=timestamp '2014-09-08 13:52:41' and pl.linktypeid=1 and pl.creationdate>=timestamp '2011-10-06 21:41:26' and v.votetypeid=2;
